// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

/// @title ShardeumToken - A minimal ERC-20 token for Shardeum
/// @notice Deploy your own token on Shardeum with mint/burn support
contract ShardeumToken {
    string public name;
    string public symbol;
    uint8 public constant decimals = 18;
    uint256 public totalSupply;
    address public owner;

    mapping(address => uint256) public balanceOf;
    mapping(address => mapping(address => uint256)) public allowance;

    event Transfer(address indexed from, address indexed to, uint256 value);
    event Approval(address indexed owner, address indexed spender, uint256 value);
    event Mint(address indexed to, uint256 amount);
    event Burn(address indexed from, uint256 amount);

    modifier onlyOwner() {
        require(msg.sender == owner, "ShardeumToken: caller is not the owner");
        _;
    }

    constructor(string memory _name, string memory _symbol, uint256 _initialSupply) {
        name = _name;
        symbol = _symbol;
        owner = msg.sender;
        _mint(msg.sender, _initialSupply * 10 ** decimals);
    }

    // ── ERC-20 Core ──────────────────────────────────────────────────────────

    function transfer(address to, uint256 amount) external returns (bool) {
        _transfer(msg.sender, to, amount);
        return true;
    }

    function approve(address spender, uint256 amount) external returns (bool) {
        allowance[msg.sender][spender] = amount;
        emit Approval(msg.sender, spender, amount);
        return true;
    }

    function transferFrom(address from, address to, uint256 amount) external returns (bool) {
        uint256 allowed = allowance[from][msg.sender];
        require(allowed >= amount, "ShardeumToken: insufficient allowance");
        allowance[from][msg.sender] = allowed - amount;
        _transfer(from, to, amount);
        return true;
    }

    // ── Mint & Burn ──────────────────────────────────────────────────────────

    function mint(address to, uint256 amount) external onlyOwner {
        _mint(to, amount);
    }

    function burn(uint256 amount) external {
        require(balanceOf[msg.sender] >= amount, "ShardeumToken: burn amount exceeds balance");
        balanceOf[msg.sender] -= amount;
        totalSupply -= amount;
        emit Burn(msg.sender, amount);
        emit Transfer(msg.sender, address(0), amount);
    }

    // ── Internal ─────────────────────────────────────────────────────────────

    function _transfer(address from, address to, uint256 amount) internal {
        require(to != address(0), "ShardeumToken: transfer to zero address");
        require(balanceOf[from] >= amount, "ShardeumToken: insufficient balance");
        balanceOf[from] -= amount;
        balanceOf[to] += amount;
        emit Transfer(from, to, amount);
    }

    function _mint(address to, uint256 amount) internal {
        require(to != address(0), "ShardeumToken: mint to zero address");
        totalSupply += amount;
        balanceOf[to] += amount;
        emit Mint(to, amount);
        emit Transfer(address(0), to, amount);
    }
}

contracts/SimpleStorage.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

/// @title SimpleStorage - A basic key-value store contract
/// @notice Demonstrates state variables, events, and access control on Shardeum
contract SimpleStorage {
    uint256 public value;
    address public owner;

    event ValueUpdated(address indexed updatedBy, uint256 oldValue, uint256 newValue);
    event OwnershipTransferred(address indexed oldOwner, address indexed newOwner);

    modifier onlyOwner() {
        require(msg.sender == owner, "SimpleStorage: caller is not the owner");
        _;
    }

    constructor(uint256 _initialValue) {
        value = _initialValue;
        owner = msg.sender;
        emit ValueUpdated(msg.sender, 0, _initialValue);
    }

    /// @notice Update the stored value (owner only)
    function setValue(uint256 _newValue) external onlyOwner {
        uint256 old = value;
        value = _newValue;
        emit ValueUpdated(msg.sender, old, _newValue);
    }

    /// @notice Transfer ownership to a new address
    function transferOwnership(address _newOwner) external onlyOwner {
        require(_newOwner != address(0), "SimpleStorage: new owner is zero address");
        emit OwnershipTransferred(owner, _newOwner);
        owner = _newOwner;
    }
}

